    // Navigate to the app
    await page.goto('/');

    // Wait for app to load
    await page.waitForLoadState('networkidle');

    // Wait for React/PixiJS to initialize
    await page.waitForTimeout(2000);

    // Check for critical elements
    await expect(page.locator('body')).toBeVisible();

    // Report errors if any
    if (errors.length > 0) {
      console.log('Console errors found:');
      errors.forEach((e, i) => console.log(`  ${i + 1}. ${e}`));
    }

    // Fail if there are errors
    expect(errors, `Found ${errors.length} console errors`).toHaveLength(0);
  });

  test('PixiJS canvas initializes correctly', async ({ page }) => {
    const errors: string[] = [];

    page.on('console', (msg) => {
      if (msg.type() === 'error') {
        errors.push(msg.text());
      }
    });

    page.on('pageerror', (error) => {
      errors.push(`Page Error: ${error.message}`);
    });

    await page.goto('/');
    await page.waitForLoadState('networkidle');
    await page.waitForTimeout(2000);

    // Check that canvas element exists and is visible
    const canvas = page.locator('canvas').first();
    await expect(canvas).toBeVisible();

    // Verify canvas has proper dimensions
    const box = await canvas.boundingBox();
    expect(box).not.toBeNull();
    expect(box!.width).toBeGreaterThan(100);
    expect(box!.height).toBeGreaterThan(100);

    // Verify no errors during canvas init
    expect(errors, `Canvas init errors: ${errors.join(', ')}`).toHaveLength(0);
  });

  test('header displays app title and branding', async ({ page }) => {
    await page.goto('/');
    await page.waitForLoadState('networkidle');

    // Check header title - expected: "MMS Fractal Planner"
    const title = page.getByRole('heading', { name: /MMS Fractal Planner/i });
    await expect(title).toBeVisible();

    // Check subtitle - expected: "128 trains × 12 years"
    const subtitle = page.getByText(/128 trains/i);
    await expect(subtitle).toBeVisible();
  });

  test('LOD indicator shows current zoom level', async ({ page }) => {
    await page.goto('/');
    await page.waitForLoadState('networkidle');

    // LOD indicator should show one of: "LOD 0: Heatmap", "LOD 1: Bars", "LOD 2: Capsules"
    const lodIndicator = page.getByText(/LOD \d:/i);
    await expect(lodIndicator).toBeVisible();

    // Get the LOD text and verify it matches expected format
    const lodText = await lodIndicator.textContent();
    expect(lodText).toMatch(/LOD [012]: (Heatmap|Bars|Capsules)/);
  });

  test('canvas area is interactive (has proper ARIA)', async ({ page }) => {
    await page.goto('/');
    await page.waitForLoadState('networkidle');

    // Canvas container should have role="application" for accessibility
    const canvasContainer = page.getByRole('application', { name: /Fractal Planner Canvas/i });
    await expect(canvasContainer).toBeVisible();
  });

  test('px/h scale indicator is displayed', async ({ page }) => {
    await page.goto('/');
    await page.waitForLoadState('networkidle');

    // Should show pixels per hour indicator
    const scaleIndicator = page.getByText(/px\/h/i);
    await expect(scaleIndicator).toBeVisible();
  });
});

